const ACCESS_TOKEN = '105_PKbmSIiiReZeyBZUQPsAhgUubS-QHger6cd1F_eTL7uQoJdJTGB3JKqmNZBoMFk7NEyiDy40UAGkU5PCoA5tgdrnza9RYtmyqPn2m7KMroPqr3Oa2HvthiE__0MXQKdAJAATN';

function httpsGet(url) {
  return new Promise((resolve, reject) => {
    https.get(url, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        try {
          resolve(JSON.parse(data));
        } catch(e) {
          resolve(data);
        }
      });
    }).on('error', reject);
  });
}

async function main() {
  // 1. 先获取用户列表（所有关注者）
  console.log('获取关注者列表...');
  const userList = await httpsGet(`https://api.weixin.qq.com/cgi-bin/user/get?access_token=${ACCESS_TOKEN}&next_openid=`);
  console.log('响应:', JSON.stringify(userList, null, 2));

  if (userList.errcode) {
    console.log('获取用户列表失败:', userList.errmsg);
    return;
  }

  const openIds = userList.data?.openid || [];
  console.log(`\n共 ${userList.total} 个关注者，本次获取 ${userList.count} 个`);

  if (openIds.length === 0) {
    console.log('没有获取到任何用户');
    return;
  }

  // 2. 尝试获取用户基本信息（逐个）
  console.log('\n获取用户基本信息...');
  for (const openid of openIds.slice(0, 5)) { // 先查看前5个
    const info = await httpsGet(`https://api.weixin.qq.com/cgi-bin/user/info?access_token=${ACCESS_TOKEN}&openid=${openid}&lang=zh_CN`);
    console.log(`\n用户: ${openid}`);
    console.log(JSON.stringify(info, null, 2));
  }
}

main().catch(console.error);
